import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Booking() {
  const [bookings, setBookings] = useState([]);
  const [userName, setUserName] = useState("");
  const [serviceName, setServiceName] = useState("");

  const navigate = useNavigate();

  const fetchBookings = () => {
    const token = localStorage.getItem("token");

    axios
      .get("http://localhost:5000/api/bookings", {
        headers: {
          Authorization: `Bearer ${token}`
        }
      })
      .then(res => setBookings(res.data))
      .catch(err => console.log(err));
  };

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/login");
      return;
    }

    fetchBookings();
  }, [navigate]);

  const bookService = () => {
    const token = localStorage.getItem("token");

    axios
      .post(
        "http://localhost:5000/api/bookings",
        {
          userName,
          serviceName
        },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      )
      .then(() => {
        alert("Booked!");
        fetchBookings();
      })
      .catch(err => console.log(err));
  };

  const logout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
  <div style={styles.page}>
    
    <div style={styles.blob}></div>

    <div style={styles.topBar}>
      <h2 style={styles.title}>Booking Dashboard</h2>
      <button style={styles.logoutBtn} onClick={logout}>
        Logout
      </button>
    </div>

    <div style={styles.grid}>
      {/* FORM CARD */}
      <div style={styles.card}>
        <h3>Create Booking</h3>

        <input
          style={styles.input}
          placeholder="Your Name"
          onChange={(e) => setUserName(e.target.value)}
        />

        <input
          style={styles.input}
          placeholder="Service Name"
          onChange={(e) => setServiceName(e.target.value)}
        />

        <button style={styles.primaryBtn} onClick={bookService}>
          Book Service
        </button>
      </div>

      {/* LIST CARD */}
      <div style={styles.card}>
        <h3>Your Bookings</h3>

        {bookings.length === 0 && (
          <p style={{ opacity: 0.6 }}>No bookings yet</p>
        )}

        {bookings.map((b, i) => (
          <div key={i} style={styles.item}>
            <span>{b.userName}</span>
            <span style={{ opacity: 0.7 }}>→</span>
            <span>{b.serviceName}</span>
          </div>
        ))}
      </div>
    </div>

  </div>
);
}

const styles = {
  page: {
    minHeight: "100vh",
    padding: "30px",
    background: "radial-gradient(circle at top, rgba(59,130,246,0.25), transparent 50%), linear-gradient(135deg, #0f172a, #111827)",
    color: "white",
    fontFamily: "Arial"
  },

  topBar: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "30px"
  },

  title: {
    fontSize: "24px",
    fontWeight: "bold",
    letterSpacing: "1px"
  },

  logoutBtn: {
    padding: "8px 14px",
    borderRadius: "8px",
    border: "none",
    background: "#ef4444",
    color: "white",
    cursor: "pointer"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px"
  },

  card: {
  background: "rgba(255,255,255,0.06)",
  backdropFilter: "blur(14px)",
  border: "1px solid rgba(255,255,255,0.08)",
  borderRadius: "18px",
  padding: "20px",
  boxShadow: "0 10px 40px rgba(0,0,0,0.4)"
},

  input: {
    width: "100%",
    padding: "10px",
    margin: "10px 0",
    borderRadius: "10px",
    border: "1px solid rgba(255,255,255,0.1)",
    background: "rgba(255,255,255,0.05)",
    color: "white",
    outline: "none"
  },

  primaryBtn: {
  width: "100%",
  padding: "12px",
  borderRadius: "12px",
  border: "none",
  background: "linear-gradient(135deg, #3b82f6, #2563eb)",
  color: "white",
  fontWeight: "bold",
  cursor: "pointer"
},

  item: {
    display: "flex",
    justifyContent: "space-between",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "10px",
    background: "rgba(255,255,255,0.05)"
  },

  blob: {
  position: "absolute",
  width: "300px",
  height: "300px",
  background: "#3b82f6",
  filter: "blur(120px)",
  opacity: 0.2,
  top: "20%",
  left: "10%",
  zIndex: 0
}
};

export default Booking;
